import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';
import Login from './components/Login';
import Register from './components/Register';
import AdminDashboard from './components/AdminDashboard';
import AdminProducts from './components/AdminProducts';
import AdminPartners from './components/AdminPartners';
import PartnerDashboardNew from './components/PartnerDashboardNew';
import PartnerProducts from './components/PartnerProducts';
import Sales from './components/Sales';
import { LayoutDashboard, Package, Users, ShoppingCart, LogOut } from 'lucide-react';

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    // Check if user is logged in (get from sessionStorage)
    const tabId = sessionStorage.getItem('tabId');
    const storedUser = sessionStorage.getItem(`user_${tabId}`);
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
  }, []);

  const handleLogout = () => {
    const tabId = sessionStorage.getItem('tabId');
    sessionStorage.removeItem(`user_${tabId}`);
    sessionStorage.removeItem(`token_${tabId}`);
    setUser(null);
  };

  return (
    <Router>
      <div style={{ display: 'flex', minHeight: '100vh', background: '#f8fafc' }}>
        {user && (
          <div style={{
            width: '250px',
            background: 'linear-gradient(180deg, #1e293b 0%, #0f172a 100%)',
            color: 'white',
            padding: '2rem 0',
            boxShadow: '4px 0 20px rgba(0,0,0,0.1)',
            position: 'fixed',
            height: '100vh',
            left: 0,
            top: 0,
            zIndex: 1000
          }}>
            {/* Logo Section */}
            <div style={{
              padding: '0 1.5rem',
              marginBottom: '2rem',
              borderBottom: '1px solid rgba(255,255,255,0.1)',
              paddingBottom: '1.5rem'
            }}>
              <h2 style={{
                fontSize: '1.5rem',
                fontWeight: '700',
                background: 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                marginBottom: '0.5rem'
              }}>
                Sales ERP
              </h2>
              <p style={{
                fontSize: '0.875rem',
                color: '#94a3b8',
                fontWeight: '500'
              }}>
                {user.userRole} Portal
              </p>
              <p style={{
                fontSize: '0.75rem',
                color: '#64748b',
                marginTop: '0.25rem'
              }}>
                {user.email}
              </p>
            </div>

            {/* Navigation Links */}
            <nav style={{ padding: '0 1rem' }}>
              {user?.userRole === 'Admin' && (
                <>
                  <Link to="/dashboard" style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.75rem',
                    padding: '0.875rem 1rem',
                    color: 'white',
                    textDecoration: 'none',
                    borderRadius: '8px',
                    marginBottom: '0.5rem',
                    transition: 'all 0.2s ease',
                    fontWeight: '500',
                    fontSize: '0.95rem'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)';
                    e.currentTarget.style.transform = 'translateX(5px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = 'transparent';
                    e.currentTarget.style.transform = 'translateX(0)';
                  }}>
                    <LayoutDashboard size={20} />
                    Dashboard
                  </Link>

                  <Link to="/products" style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.75rem',
                    padding: '0.875rem 1rem',
                    color: 'white',
                    textDecoration: 'none',
                    borderRadius: '8px',
                    marginBottom: '0.5rem',
                    transition: 'all 0.2s ease',
                    fontWeight: '500',
                    fontSize: '0.95rem'
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)';
                    e.currentTarget.style.transform = 'translateX(5px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = 'transparent';
                    e.currentTarget.style.transform = 'translateX(0)';
                  }}>
                    <Package size={20} />
                    Products
                  </Link>

                  <Link to="/partners" style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.75rem',
                    padding: '0.875rem 1rem',
                    color: 'white',
                    textDecoration: 'none',
